import { NextRequest, NextResponse } from 'next/server'
import { prisma }  from '@/lib/prisma'
import { sendPasswordResetEmail } from '@/lib/email'
import { createHash, randomBytes } from 'crypto'

export async function POST(req: NextRequest) {
  const { email } = await req.json()
  if (!email) return NextResponse.json({ error: 'Email required' }, { status: 400 })

  // Always return success to prevent email enumeration
  const user = await prisma.user.findFirst({ where: { email: email.toLowerCase() } })

  if (user) {
    // Generate a secure token
    const token = randomBytes(32).toString('hex')
    const expires = new Date(Date.now() + 30 * 60 * 1000) // 30 min

    // Store token hash in DB
    await prisma.user.update({
      where: { id: user.id },
      data: {
        resetToken:   createHash('sha256').update(token).digest('hex'),
        resetExpires: expires,
      } as any,
    }).catch(() => null) // field may not exist yet — see schema note below

    const resetUrl = `${process.env.NEXT_PUBLIC_APP_URL}/reset-password?token=${token}&email=${encodeURIComponent(email)}`
    await sendPasswordResetEmail(email, user.alias, resetUrl)
  }

  return NextResponse.json({ ok: true, message: 'If that email exists, a reset link has been sent.' })
}
